css:
@page {
    size: A4;
    margin-top: 20mm;
    margin-bottom: 15mm;
    margin-left: 6mm;
    margin-right: 6mm;
}

body,
.print-format {
    font-family: "Inter", "Segoe UI", sans-serif;
    color: #111827;
    font-size: 10px;
    line-height: 1.35;
    background: #ffffff;
}

.print-format {
    padding-top: 2mm !important;
    padding-bottom: 5mm !important;
    padding-left: 3mm !important;
    padding-right: 3mm !important;
}

table {
    width: 100%;
    border-collapse: collapse;
}

tr {
    page-break-inside: avoid !important;
}

.hidden-pdf {
    display: block;
}

.visible-pdf {
    display: none !important;
}

.doc-info {
    margin-bottom: 10px;
    border-bottom: 2px solid #111827;
    padding-bottom: 6px;
}

.doc-info-table {
    width: 100%;
}

.doc-info-table td {
    vertical-align: top;
}

.doc-info-left {
    width: 50%;
}

.doc-info-right {
    width: 50%;
    text-align: right;
}

.doc-title {
    font-size: 18px;
    font-weight: 800;
    color: #111827;
    line-height: 1;
}

.doc-number {
    margin-top: 3px;
    font-size: 10px;
    color: #6b7280;
    font-weight: 600;
}

.info-pairs {
    width: auto;
    margin-left: auto;
}

.info-pairs td {
    padding: 1px 6px;
    font-size: 10px;
    border: none;
}

.info-label {
    color: #6b7280;
    font-weight: 600;
    text-align: right;
    white-space: nowrap;
}

.info-value {
    text-align: left;
    font-weight: 600;
}

.items-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 10px;
    page-break-inside: auto;
}

.items-table thead {
    display: table-header-group;
}

.items-table th {
    background: #111827;
    color: #ffffff;
    padding: 6px 8px;
    font-size: 10px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border: 1px solid #111827;
}

.items-table td {
    padding: 6px 8px;
    border: 1px solid #e5e7eb;
    font-size: 10px;
}

.items-table tbody tr:nth-child(even) {
    background: #f9fafb;
}

.items-table td.num {
    text-align: right;
}

.items-table td.desc {
    text-align: left;
}

.total-row td {
    font-weight: 700;
    font-size: 12px;
    background: #f3f4f6;
    border-top: 2px solid #111827;
}

.amount-in-words {
    margin: 8px 0;
    font-size: 10px;
    color: #374151;
}

.amount-in-words span {
    font-weight: 700;
}

.remarks-section {
    margin: 8px 0;
    padding: 6px 8px;
    background: #f9fafb;
    border: 1px solid #e5e7eb;
    border-radius: 3px;
}

.remarks-section .remarks-label {
    font-weight: 700;
    color: #6b7280;
    font-size: 9px;
    text-transform: uppercase;
    margin-bottom: 2px;
}

.signatures {
    width: 100%;
    border-collapse: collapse;
    margin-top: 50px;
}

.signatures td {
    width: 50%;
    text-align: center;
    padding: 10px;
    vertical-align: top;
}

.sign-line {
    border-top: 1px solid #333;
    margin-top: 50px;
    padding-top: 5px;
    font-weight: bold;
    font-size: 10px;
}
